sp_widget.client_script:
api.controller = function() {
    var c = this;

    // A counter to give each simulated instance a distinct name/URL number
    var connectionCounter = 1;

    // Triggers when the user clicks "+ New Connection"
    c.newConnection = function() {
        // 1. Construct a new card object dynamically
        var simulatedConnection = {
            id: 'conn_' + Date.now(), // Unique ID using standard millisecond timestamp
            name: 'demo ' + connectionCounter,
            url: 'https://sysusademo' + connectionCounter + '.service-now.com/',
            username: 'bareen.makhdoomi',
            lastUpdated: new Date().toLocaleString(), // Captures your current browser date & time
            status: connectionCounter % 2 !== 0 ? 'Active' : 'Inactive', // Toggles status for visual variance
            selected: connectionCounter === 2 // Card 2 gets the active gradient ring from image_395789.png
        };

        // 2. Append the new object directly into the array
        c.data.connections.push(simulatedConnection);

        // 3. Increment our counter so the next card created is numbered correctly
        connectionCounter++;
    };

    c.connect = function(conn) {
        console.log("Initiating live sync handshake with: " + conn.name);
    };

    c.edit = function(conn) {
        console.log("Opening editing workspace configuration map for: " + conn.name);
    };

    // Triggers when the user clicks "Delete" on a card
    c.delete = function(conn) {
        // Find where this card lives inside our array
        var index = c.data.connections.indexOf(conn);
        if (index > -1) {
            // Slice it out of the array. AngularJS automatically updates the UI layout.
            c.data.connections.splice(index, 1);
            console.log("Safely purged cached workspace definition for: " + conn.name);
        }
    };
};

sp_widget.css:
.tn-connections-widget {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  color: #0f172a;
  
  .page-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 24px;
    
    .page-title {
      font-size: 26px;
      font-weight: 700;
      color: #0c63e7;
      margin: 0 0 4px 0;
    }
    
    .page-subtitle {
      color: #64748b;
      font-size: 14px;
      margin: 0;
    }
    
    .btn-primary {
      background: #0c63e7;
      color: white;
      border: none;
      padding: 12px 24px;
      border-radius: 8px;
      font-weight: 600;
      cursor: pointer;
      box-shadow: 0 4px 10px rgba(12, 99, 231, 0.3);
      transition: all 0.2s ease;
      &:hover { background: #0a52c2; transform: translateY(-1px); }
    }
  }

  .security-banner {
    display: flex;
    align-items: center;
    background: #ffffff;
    border: 1px solid #e2e8f0;
    border-radius: 12px;
    padding: 16px 20px;
    margin-bottom: 30px;
    gap: 16px;
    
    .icon-circle {
      color: #0c63e7;
      font-size: 22px;
      display: flex;
      align-items: center;
    }
    
    .banner-text {
      strong { display: block; font-size: 14px; color: #0f172a; margin-bottom: 2px; }
      p { margin: 0; font-size: 13px; color: #64748b; }
    }
  }

  .connections-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 24px;

    .connection-card {
      background: #ffffff;
      border: 1px solid #e2e8f0;
      border-radius: 16px;
      padding: 24px;
      box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);
      transition: all 0.2s ease;
      
      /* Active Highlight Matching Image */
      &.selected-card {
        background: linear-gradient(135deg, #eff6ff 0%, #e0eafc 100%);
        border-color: #bfdbfe;
        box-shadow: 0 10px 20px -5px rgba(12, 99, 231, 0.15);
      }

      .card-top {
        display: flex;
        justify-content: space-between;
        align-items: flex-start;
        margin-bottom: 4px;
        
        .conn-name {
          font-size: 18px;
          font-weight: 700;
          color: #0c63e7;
          margin: 0;
        }

        .status-badge {
          padding: 4px 10px;
          border-radius: 20px;
          font-size: 12px;
          font-weight: 600;
          display: flex;
          align-items: center;
          gap: 6px;
          
          &.active-badge { background: #dbeafe; color: #0c63e7; }
          &.inactive-badge { background: #fee2e2; color: #ef4444; }
        }
      }

      .conn-url {
        font-size: 13px;
        color: #94a3b8;
        text-decoration: none;
        display: block;
        margin-bottom: 20px;
        &:hover { text-decoration: underline; color: #0c63e7;}
      }

      .conn-details {
        display: flex;
        justify-content: space-between;
        margin-bottom: 24px;
        
        .detail-group {
          label { display: block; font-size: 11px; color: #94a3b8; margin-bottom: 4px; text-transform: uppercase; letter-spacing: 0.5px;}
          span { font-size: 13px; font-weight: 600; color: #334155; }
        }
        .text-right { text-align: right; }
      }

      .card-actions {
        display: flex;
        gap: 12px;
        
        .btn-action {
          padding: 8px 16px;
          border-radius: 6px;
          font-size: 13px;
          font-weight: 600;
          cursor: pointer;
          border: none;
          display: flex;
          align-items: center;
          gap: 6px;
          transition: all 0.2s ease;
        }
        
        .btn-connect { background: #eff6ff; color: #0c63e7; }
        .btn-connect:hover { background: #dbeafe; }
        
        .btn-edit { background: #f1f5f9; color: #475569; }
        .btn-edit:hover { background: #e2e8f0; }
        
        .btn-delete { background: #fef2f2; color: #ef4444; }
        .btn-delete:hover { background: #fee2e2; }
      }
    }
  }
}

sp_widget.script:
(function() {
    /* Initialize an empty array.
       Later, this will be replaced with a GlideRecord query 
       to pull saved connection records from a custom table. */
    data.connections = [];
})();
